import { Component } from 'react';
import './App.css';
//import './DarkApp.css'
import Navbar from './components/Navbar'
import Contenido from './components/Contenido'
import seccionesWeb from './data/secciones.json'

const secciones = seccionesWeb.secciones

class App extends Component {
  state = {
    temaOscuro: false,
  }

  cambiarTema = () => {
    console.log('Cambiando estado')
    this.setState({ temaOscuro: !this.state.temaOscuro });
  }

  actualizarEstilos = () => {
    const { temaOscuro } = this.state;
    const linkElement = document.getElementById('app-styles');

    if (temaOscuro) {
      linkElement.href = './DarkApp.css';
    } else {
      linkElement.href = './App.css';
    }
  }

  componentDidMount() {
    this.actualizarEstilos();
  }

  componentDidUpdate() {
    this.actualizarEstilos();
  }
  render (){

    return (
      <div className='App'>
        <Navbar 
        temaOscuro={this.temaOscuro}
        secciones={secciones}/>
        <Contenido
        temaOscuro={this.state.temaOscuro}
        cambiarTema={this.cambiarTema} 
        secciones={secciones}/>
      </div>
    );
  }
}

export default App;
